import React from 'react';
import './TeamDisplay.css';  // Make sure to include any necessary styling

const TeamDisplay = ({ teams, showDetails, calculateAverageRating }) => {
  return (
    <div className="team-display-container">
      {teams.map((team, index) => (
        <div key={index} className="team-card">
          <h4>Team {index + 1}: {team.length} players</h4>
          <p className="average-rating">Average Rating: {calculateAverageRating(team).toFixed(2)}</p>
          <table className="table table-striped table-bordered">
            <thead>
              <tr>
                <th>Name</th>
                {showDetails && <th>Rating</th>}
              </tr>
            </thead>
            <tbody>
              {team.map((player) => (
                <tr key={player.id}>
                  <td>{player.name}</td>
                  {showDetails && <td>{player.rating}</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ))}
    </div>
  );
};

export default TeamDisplay;
